def generate():
    path = CACHE / "synthetic_code_reasoning.pkl"
    texts = []
    for s in SAMPLES:
        t = f"<|user|>\n{s['problem']}\n<|assistant|>\n{s['code']}\n<|end|>"
        texts.append(t)
    pickle.dump(texts, open(path, "wb"))
    print(f"Generated {len(texts)} latent samples -> {path}")
    print(f"Total tokens: {sum(len(t.split()) for t in texts):,}")

if __name__ == "__main__":
    generate()
